module shift_register_16bit (
    input wire clk,
    input wire rst,
    input wire load,
    input wire [15:0] parallel_in,
    output wire serial_out
);

    reg [15:0] data_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            data_reg <= 16'b0;
        end else if (load) begin
            data_reg <= parallel_in;
        end else begin
            data_reg <= {data_reg[14:0], 1'b0};
        end
    end

    assign serial_out = data_reg[15];

endmodule
